    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function parseJsonObject(rawText) {
  const raw = safeText(rawText);
  if (!raw) return null;

  const direct = safeJsonParse(raw, null);
  if (direct && typeof direct === 'object') return direct;

  const fence = raw.match(/\x60\x60\x60(?:json)?\s*([\s\S]*?)\x60\x60\x60/i);
  if (fence) {
    const parsedFence = safeJsonParse(fence[1], null);
    if (parsedFence && typeof parsedFence === 'object') return parsedFence;
  }

  const firstObj = raw.indexOf('{');
  const lastObj = raw.lastIndexOf('}');
  if (firstObj >= 0 && lastObj > firstObj) {
    const parsedObj = safeJsonParse(raw.slice(firstObj, lastObj + 1), null);
    if (parsedObj && typeof parsedObj === 'object') return parsedObj;
  }

  return null;
}

function tokenizeSentences(text) {
  const normalized = normalizeText(text).replace(/\s+/g, ' ');
  if (!normalized) return [];

  const matches = normalized.match(/[^.!?…]+(?:[.!?…]+(?:["'”’)\]]+)*)|[^.!?…]+$/g) ?? [];
  const sentences = matches.map((item) => item.trim()).filter(Boolean);
  return sentences.length > 0 ? sentences : [normalized];
}

function normalizeSceneItem(item, index) {
  const source = item && typeof item === 'object' ? item : {};
  const order = asInt(source.order, index + 1, 1, 10000);
  const sceneId = safeText(source.scene_id, safeText(source.chunk_key, 'scene_' + String(order).padStart(2, '0')));
  const narrationText = safeText(source.narration_text, safeText(source.text));

