const input = $json ?? {};
const items = Array.isArray(input.media_video_items)
  ? input.media_video_items
  : (Array.isArray(input.media_image_items) ? input.media_image_items : []);
const driveFileId = String(input.id ?? input.fileId ?? input.data?.id ?? '').trim();
const driveUrl = String(input.webViewLink ?? input.alternateLink ?? input.data?.webViewLink ?? '').trim();

const statusOf = (item) => String(item?.video_status ?? item?.image_status ?? '');
const failedCount = items.filter((item) => statusOf(item) === 'failed').length;
const generatedCount = items.filter((item) => statusOf(item) === 'generated').length;

let status = 'success';
let errorReason = null;

if (items.length === 0) {
  status = 'failed';
  errorReason = 'empty_items';
} else if (failedCount > 0) {
  status = generatedCount > 0 ? 'partial_failed' : 'failed';
  errorReason = generatedCount > 0 ? 'partial_failures' : 'all_failed';
}

if (!driveFileId) {
  if (status === 'success') {
    status = 'partial_failed';
  }
  errorReason = errorReason ?? 'drive_export_failed';
}

return {
  ...input,
  workflow: 'text-to-videos-veo3',
  request_id: String(input.request_id ?? ''),
  status,
  items,
  drive_exports: driveFileId ? [{
    drive_file_id: driveFileId,
    drive_url: driveUrl,
    mime_type: 'application/json',
    file_name: String(input.export_file_name ?? ''),
  }] : [],
  error_reason: errorReason,
};

const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function pickFirstString(values) {
  for (const value of values) {
    const text = String(value ?? '').trim();
    if (text) return text;
  }
  return '';
}

function pickResponseSource(value) {
  const candidates = [value, value?.body, value?.data, value?.response, value?.result, value?.output, value?.json];
  for (const candidate of candidates) {
    if (candidate && typeof candidate === 'object') return candidate;
  }
  return value ?? {};
}

function normalizeBaseUrl(baseUrl) {
  return String(baseUrl ?? '').trim().replace(/\/$/, '');
}

function buildStatusUrl(baseUrl, statusPath, jobId) {
  const normalizedBase = normalizeBaseUrl(baseUrl);
  const normalizedPath = String(statusPath ?? '/jobs').trim() || '/jobs';
  const path = normalizedPath.startsWith('/') ? normalizedPath : '/' + normalizedPath;
  const safeJobId = encodeURIComponent(String(jobId ?? '').trim());
  if (!normalizedBase) return '';
  return normalizedBase + path.replace(/\/$/, '') + '/' + safeJobId;
}

const source = pickResponseSource(input);
const errorText = safeText(input.error?.message ?? input.error ?? source.error?.message ?? source.error, '');

const requestId = safeText(
  input.request_id,
  safeText(source.request_id, safeText(source.job_id, safeText(source.id, 'req-' + Date.now().toString(36)))),
);

const jobId = pickFirstString([
  source.job_id,
  source.jobId,
  source.id,
  source.data?.job_id,
  source.data?.jobId,
  source.data?.id,
  source.result?.job_id,
  source.result?.jobId,
  source.result?.id,
  source.job?.id,
  source.output?.job_id,
  source.output?.jobId,
  source.output?.id,
  requestId,
]);

const jobStatus = pickFirstString([
  source.status,
  source.state,
  source.job_status,
  source.jobStatus,
  source.data?.status,
  source.data?.state,
  source.result?.status,
  source.result?.state,
  source.output?.status,
  source.output?.state,
  source.job?.status,
]).toLowerCase();

let image = pickFirstString([
  source.image,
  source.image_url,
  source.imageUrl,
  source.url,
  source.output_url,
  source.outputUrl,
  source.data?.image,
  source.data?.image_url,
  source.data?.imageUrl,
  source.data?.url,
  source.result?.image,
  source.result?.image_url,
  source.result?.imageUrl,
  source.result?.url,
  source.output?.image,
  source.output?.image_url,
  source.output?.imageUrl,
  source.output?.url,
  Array.isArray(source.output) ? source.output[0]?.url : '',
]);

if (!image) {
  const base64 = pickFirstString([
    source.image_base64,
    source.imageBase64,
    source.b64_json,
    source.data?.image_base64,
    source.data?.imageBase64,
    source.result?.image_base64,
    source.result?.imageBase64,
    source.output?.image_base64,
    source.output?.imageBase64,
  ]).replace(/^data:image\/[a-zA-Z0-9+.-]+;base64,/, '');
  if (base64) {
    image = 'data:image/png;base64,' + base64;
  }
}

const video = pickFirstString([
  source.video,
  source.video_url,
  source.videoUrl,
  source.data?.video,
  source.data?.video_url,
  source.data?.videoUrl,
  source.result?.video,
  source.result?.video_url,
  source.result?.videoUrl,
  source.output?.video,
  source.output?.video_url,
  source.output?.videoUrl,
]);

const jobCreatedStatus = jobStatus || (image || video ? 'done' : 'pending');
const timeoutMsRaw = Number(input.image_timeout_ms ?? 900000);
const timeoutMs = Number.isFinite(timeoutMsRaw) ? Math.max(10000, Math.floor(timeoutMsRaw)) : 900000;
const intervalRaw = Number(input.image_poll_interval_seconds ?? 3);
const pollIntervalSeconds = Number.isFinite(intervalRaw) ? Math.max(1, Math.floor(intervalRaw)) : 10;
const startedAt = safeText(input.image_poll_started_at, new Date().toISOString());
const deadlineAt = safeText(input.image_poll_deadline_at, new Date(Date.now() + timeoutMs).toISOString());
const pollState = errorText
  ? 'failed'
  : ['failed', 'error', 'cancelled', 'canceled', 'timeout', 'aborted', 'rejected'].includes(jobCreatedStatus)
    ? 'failed'
    : ['done', 'succeeded', 'success', 'completed', 'complete', 'ready', 'finished'].includes(jobCreatedStatus) || image || video
      ? 'done'
      : 'pending';

const imageStatus = pollState === 'done'
  ? (image || video ? 'generated' : 'failed')
  : pollState === 'failed' ? 'failed' : 'pending';

const errorReason = pollState === 'failed'
  ? errorText || (image || video ? null : 'image_job_create_missing_asset')
  : null;

return {
  ...input,
  request_id: requestId,
  image_job_id: jobId,
  image_job_status: jobCreatedStatus,
  image_job_status_url: buildStatusUrl(input.image_api_base_url, input.image_job_status_path, jobId),
  image_poll_state: pollState,
  image_poll_started_at: startedAt,
  image_poll_deadline_at: deadlineAt,
  image_poll_interval_seconds: pollIntervalSeconds,
  image: image || video || '',
  video: video || image || '',
  image_url: image || video || '',
  video_url: video || image || '',
  image_status: imageStatus,
  video_status: imageStatus,
  error_reason: errorReason,
};

